export class ImageToTextPipeline extends (/** @type {new (options: TextImagePipelineConstructorArgs) => ... */ (Pipeline)) {
    constructor(options) {
        super(options);
    }

    /** @type {ImageToTextPipelineCallback} */
    async _call(images, generate_kwargs = {}) {
        const isBatched = Array.isArray(images);
        const preparedImages = await prepareImages(images);

        const { pixel_values } = await this.processor(preparedImages);

        const toReturn = [];
        for (const batch of pixel_values) {
            batch.dims = [1, ...batch.dims]
            const output = await this.model.generate({ inputs: batch, ...generate_kwargs });
            const decoded = this.tokenizer.batch_decode(output, {
                skip_special_tokens: true,
            }).map(x => ({ generated_text: x.trim() }))
            toReturn.push(decoded);
        }

        return isBatched ? toReturn : toReturn[0];
    }
}
```

**Key Patterns**:
- Uses both `processor` (for images) and `tokenizer` (for decoding)
- `_call` method signature: `async _call(images, generate_kwargs = {})`
- Processes images via `prepareImages()` helper
- Uses `this.processor()` to get `pixel_values`
- Uses `this.model.generate()` for generation
- Uses `this.tokenizer.batch_decode()` for output
