export class DocumentQuestionAnsweringPipeline extends (/** @type {new (options: TextImagePipelineConstructorArgs) => ... */ (Pipeline)) {
    constructor(options) {
        super(options);
    }

    /** @type {DocumentQuestionAnsweringPipelineCallback} */
    async _call(image, question, generate_kwargs = {}) {
        // NOTE: For now, we only support a batch size of 1

        // Preprocess image
        const preparedImage = (await prepareImages(image))[0];
        const { pixel_values } = await this.processor(preparedImage);

        // Run tokenization on text input
        const task_prompt = `<s_docvqa><s_question>${question}</s_question><s_answer>`;
        const decoder_input_ids = this.tokenizer(task_prompt, {
            add_special_tokens: false,
            padding: true,
            truncation: true,
        }).input_ids;

        // Run model with both image and text
        const output = await this.model.generate({
            inputs: pixel_values,
            max_length: this.model.config.decoder.max_position_embeddings,
            decoder_input_ids,
            ...generate_kwargs,
        });

        // Decode output
        const decoded = this.tokenizer.batch_decode(output)[0];

        // Parse answer with regex
        const match = decoded.match(/<s_answer>(.*?)<\/s_answer>/);
        let answer = null;
        if (match && match.length >= 2) {
            answer = match[1].trim();
        }
        return [{ answer }];
    }
}
```

**Key Patterns**:
- Different signature: `async _call(image, question, generate_kwargs = {})`
- Takes image + text arguments
- Uses `processor` for image → `pixel_values`
- Uses `tokenizer` to process text input (with custom prompt format)
- Passes both `pixel_values` and `decoder_input_ids` to model
- Post-processes output with regex parsing

#### **C. ZeroShotImageClassificationPipeline** (Lines 2389-2444)
**Purpose**: Classify images with arbitrary labels (CLIP, SigLIP)

```javascript
export class ZeroShotImageClassificationPipeline extends (/** @type {new (options: TextImagePipelineConstructorArgs) => ... */ (Pipeline)) {
    constructor(options) {
        super(options);
    }

    /** @type {ZeroShotImageClassificationPipelineCallback} */
    async _call(images, candidate_labels, {
        hypothesis_template = "This is a photo of {}"
    } = {}) {
        const isBatched = Array.isArray(images);
        const preparedImages = await prepareImages(images);

        // Insert label into hypothesis template
        const texts = candidate_labels.map(x => hypothesis_template.replace('{}', x));

        // Run tokenization
        const text_inputs = this.tokenizer(texts, {
            padding: this.model.config.model_type === 'siglip' ? 'max_length' : true,
            truncation: true,
        });

        // Run processor
        const { pixel_values } = await this.processor(preparedImages);

        // Run model with both text and pixel inputs
        const output = await this.model({ ...text_inputs, pixel_values });

        // Apply softmax or sigmoid based on model type
        const function_to_apply = this.model.config.model_type === 'siglip'
            ? batch => batch.sigmoid().data
            : batch => softmax(batch.data);

        // Compare each image with each candidate label
        const toReturn = [];
        for (const batch of output.logits_per_image) {
            const probs = function_to_apply(batch);
            const result = [...probs].map((x, i) => ({
                score: x,
                label: candidate_labels[i]
            }));
            result.sort((a, b) => b.score - a.score);
            toReturn.push(result);
        }

        return isBatched ? toReturn : toReturn[0];
    }
}
```

**Key Patterns**:
- Passes both `text_inputs` and `pixel_values` to model call in single object
- Model processes vision+text together: `await this.model({ ...text_inputs, pixel_values })`
- Model-specific configuration checks (e.g., `model.config.model_type`)
- Result sorting before returning

