import { MAX_MODEL_LOAD_TIME, MAX_TEST_EXECUTION_TIME, MAX_MODEL_DISPOSE_TIME, DEFAULT_MODEL_OPTIONS } from "../init.js";

const PIPELINE_ID = "image-text-to-text";

export default () => {
  describe("Image Text to Text", () => {
    const model_id = "<tiny-test-model-id>"; // Replace with a tiny test model

    /** @type {ImageTextToTextPipeline} */
    let pipe;
    beforeAll(async () => {
      pipe = await pipeline(PIPELINE_ID, model_id, DEFAULT_MODEL_OPTIONS);
    }, MAX_MODEL_LOAD_TIME);

    it("should be an instance of ImageTextToTextPipeline", () => {
      expect(pipe).toBeInstanceOf(ImageTextToTextPipeline);
    });

    describe("batch_size=1", () => {
      it(
        "default",
        async () => {
          const dims = [64, 32, 3];
          const image = new RawImage(new Uint8ClampedArray(dims[0] * dims[1] * dims[2]).fill(128), ...dims);
          const output = await pipe(image, "Describe the image.");
          expect(output).toBeInstanceOf(Array);
          expect(output[0]).toHaveProperty("generated_text");
          expect(typeof output[0].generated_text).toBe("string");
        },
        MAX_TEST_EXECUTION_TIME,
      );
    });

    afterAll(async () => {
      await pipe.dispose();
    }, MAX_MODEL_DISPOSE_TIME);
  });
};
```

> **Note:** A suitable tiny test model (similar to `hf-internal-testing/tiny-random-...`) that uses `AutoModelForImageTextToText` should be identified and substituted for the placeholder. This is outside the scope of the code change itself.

---

## Verification

1. **Import check:** Verify `AutoModelForImageTextToText` resolves correctly by searching for it in `src/models.js` — it is defined at line 8736 and already exported.

2. **Typedef check:** Ensure `TextImagePipelineConstructorArgs` (defined at line 215 of `src/pipelines.js`) is the correct constructor type — it provides `model`, `tokenizer`, and `processor`, which is exactly what this pipeline needs.

3. **Smoke test (manual):**
   ```js
